<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu-like Desktop</title>
    <style>
        /* Reset and base dark theme */
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Ubuntu', 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            background: #1e1e2e;
            overflow: hidden;
            height: 100vh;
            user-select: none;
        }

        #desktop {
            position: absolute;
            top: 0;
            left: 0;
            width: 100vw;
            height: 100vh;
            background: linear-gradient(135deg, #2d0922 0%, #3c1038 30%, #1e1e2e 100%);
            background-size: cover;
            overflow: hidden;
        }

        /* Taskbar / dock */
        #taskbar {
            position: fixed;
            bottom: 0;
            left: 50%;
            transform: translateX(-50%);
            display: flex;
            justify-content: center;
            align-items: center;
            background: rgba(20, 20, 30, 0.9);
            backdrop-filter: blur(10px);
            border-radius: 20px 20px 0 0;
            padding: 8px 20px;
            gap: 16px;
            box-shadow: 0 -2px 20px rgba(0, 0, 0, 0.5);
            z-index: 1000;
        }

        .launcher {
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            background: transparent;
            border: none;
            color: #d4d4dc;
            font-size: 14px;
            padding: 8px 12px;
            border-radius: 16px;
            cursor: pointer;
            transition: all 0.2s;
            gap: 4px;
            min-width: 60px;
        }

        .launcher:hover {
            background: rgba(90, 60, 120, 0.5);
        }

        .launcher:active {
            background: rgba(120, 80, 160, 0.7);
        }

        .launcher-icon {
            font-size: 24px;
            line-height: 1;
        }

        /* Windows */
        .window {
            position: absolute;
            background: linear-gradient(180deg, #2b2b3c 0%, #242430 100%);
            border: 1px solid #3e3e55;
            border-radius: 10px;
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.7);
            overflow: hidden;
            display: none;
            flex-direction: column;
            min-width: 360px;
            min-height: 240px;
            z-index: 10;
            resize: both;
            overflow: auto;
        }

        .window.active {
            display: flex;
        }

        .window-header {
            background: linear-gradient(90deg, #3b2e4a, #2e2a40);
            padding: 8px 12px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            border-bottom: 1px solid #4d4663;
            color: #e0e0f0;
            font-weight: 500;
            font-size: 14px;
            cursor: grab;
            user-select: none;
        }

        .window-header:active {
            cursor: grabbing;
        }

        .window-title {
            display: flex;
            align-items: center;
            gap: 8px;
        }

        .win-close {
            background: none;
            border: none;
            color: #f1f1f1;
            font-size: 18px;
            cursor: pointer;
            width: 28px;
            height: 28px;
            display: flex;
            align-items: center;
            justify-content: center;
            border-radius: 50%;
            transition: background 0.2s;
            line-height: 1;
            padding: 0;
        }

        .win-close:hover {
            background: rgba(200, 50, 50, 0.8);
        }

        .window-content {
            padding: 12px;
            flex: 1;
            display: flex;
            flex-direction: column;
            overflow: auto;
            color: #dcdcdc;
        }

        /* Files app */
        #files-path {
            background: #1a1a26;
            padding: 6px 12px;
            border-radius: 6px;
            font-family: 'Courier New', monospace;
            font-size: 14px;
            margin-bottom: 8px;
            border: 1px solid #3d3d55;
            color: #a0a0cc;
            user-select: text;
        }

        #files-up {
            align-self: flex-start;
            background: #3b2e4a;
            border: none;
            color: #e0e0f0;
            padding: 4px 16px;
            border-radius: 6px;
            cursor: pointer;
            margin-bottom: 8px;
            font-size: 13px;
            transition: background 0.2s;
        }

        #files-up:hover {
            background: #56466b;
        }

        #files-list {
            display: flex;
            flex-wrap: wrap;
            gap: 8px;
            overflow-y: auto;
            flex: 1;
        }

        .fs-item {
            display: flex;
            align-items: center;
            gap: 6px;
            padding: 8px 12px;
            border-radius: 8px;
            cursor: pointer;
            transition: background 0.2s;
            font-size: 14px;
            width: 140px;
        }

        .fs-item:hover {
            background: rgba(90, 60, 120, 0.3);
        }

        .fs-item.folder::before {
            content: "📁";
            font-size: 18px;
        }

        .fs-item.file::before {
            content: "📄";
            font-size: 18px;
        }

        /* Notepad */
        #tabs {
            display: flex;
            gap: 2px;
            margin-bottom: 8px;
            overflow-x: auto;
            white-space: nowrap;
            min-height: 32px;
            align-items: flex-end;
        }

        .tab {
            background: #363649;
            color: #c2c2d6;
            padding: 4px 16px;
            border-radius: 8px 8px 0 0;
            cursor: pointer;
            font-size: 13px;
            transition: background 0.2s;
            border: 1px solid transparent;
            border-bottom: none;
        }

        .tab:hover {
            background: #424261;
        }

        .tab.active {
            background: #4a4a6a;
            color: #ffffff;
            border-color: #5c5c83;
        }

        #new-tab {
            align-self: flex-start;
            background: #3b2e4a;
            border: none;
            color: #e0e0f0;
            width: 30px;
            height: 30px;
            border-radius: 50%;
            font-size: 20px;
            cursor: pointer;
            margin-bottom: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: background 0.2s;
        }

        #new-tab:hover {
            background: #56466b;
        }

        #editor {
            flex: 1;
            background: #1e1e2e;
            color: #dcdcdc;
            border: 1px solid #3d3d55;
            border-radius: 6px;
            padding: 8px;
            font-family: 'Courier New', monospace;
            font-size: 14px;
            resize: none;
            outline: none;
        }

        #notepad-window .window-content {
            display: flex;
            flex-direction: column;
        }
    </style>
</head>
<body>
    <div id="desktop">
        <!-- Files Window -->
        <div id="files-window" class="window" style="top: 80px; left: 100px; width: 520px; height: 400px;">
            <div class="window-header">
                <div class="window-title">📁 Files</div>
                <button class="win-close" title="Close">✕</button>
            </div>
            <div class="window-content">
                <div id="files-path">/</div>
                <button id="files-up">⬆ Up</button>
                <div id="files-list"></div>
            </div>
        </div>

        <!-- Notepad Window -->
        <div id="notepad-window" class="window" style="top: 120px; left: 180px; width: 520px; height: 420px;">
            <div class="window-header">
                <div class="window-title">📝 Notepad</div>
                <button class="win-close" title="Close">✕</button>
            </div>
            <div class="window-content">
                <div id="tabs"></div>
                <button id="new-tab">+</button>
                <textarea id="editor" placeholder="Type here..."></textarea>
            </div>
        </div>
    </div>

    <div id="taskbar">
        <button id="open-files" class="launcher" title="Files">
            <span class="launcher-icon">📁</span>
            <span>Files</span>
        </button>
        <button id="open-notepad" class="launcher" title="Notepad">
            <span class="launcher-icon">📝</span>
            <span>Notepad</span>
        </button>
    </div>

    <script>
        (function() {
            // --- DRAG & DROP LOGIC ---
            let dragTarget = null;
            let dragOffsetX = 0;
            let dragOffsetY = 0;
            let dragWindow = null;

            document.addEventListener('mousedown', function(e) {
                const header = e.target.closest('.window-header');
                if (!header) return;
                const win = header.closest('.window');
                if (!win) return;
                // Don't drag if clicking close button inside header
                if (e.target.closest('.win-close')) return;

                dragTarget = win;
                const rect = win.getBoundingClientRect();
                dragOffsetX = e.clientX - rect.left;
                dragOffsetY = e.clientY - rect.top;
                // Bring to front
                bringToFront(win);
                e.preventDefault();
            });

            document.addEventListener('mousemove', function(e) {
                if (!dragTarget) return;
                const newLeft = e.clientX - dragOffsetX;
                const newTop = e.clientY - dragOffsetY;
                dragTarget.style.left = newLeft + 'px';
                dragTarget.style.top = newTop + 'px';
            });

            document.addEventListener('mouseup', function() {
                dragTarget = null;
            });

            // --- Z-INDEX MANAGEMENT ---
            let topZIndex = 100;
            function bringToFront(win) {
                topZIndex++;
                win.style.zIndex = topZIndex;
            }

            // Make windows bring to front on any click inside them
            document.querySelectorAll('.window').forEach(win => {
                win.addEventListener('mousedown', function(e) {
                    bringToFront(this);
                });
            });

            // --- WINDOW OPEN/CLOSE ---
            function showWindow(win) {
                win.style.display = 'flex';
                bringToFront(win);
                // Ensure it's positioned within viewport if off-screen
                const rect = win.getBoundingClientRect();
                if (rect.bottom > window.innerHeight - 60) {
                    win.style.top = Math.max(5, window.innerHeight - 60 - (rect.height || 300)) + 'px';
                }
                if (rect.right > window.innerWidth) {
                    win.style.left = Math.max(5, window.innerWidth - (rect.width || 360)) + 'px';
                }
                if (rect.top < 0) win.style.top = '5px';
                if (rect.left < 0) win.style.left = '5px';
            }

            function hideWindow(win) {
                win.style.display = 'none';
            }

            // Close buttons
            document.querySelectorAll('.win-close').forEach(btn => {
                btn.addEventListener('click', function(e) {
                    e.stopPropagation();
                    const win = this.closest('.window');
                    if (win) hideWindow(win);
                });
            });

            // Launcher buttons
            document.getElementById('open-files').addEventListener('click', function() {
                const win = document.getElementById('files-window');
                showWindow(win);
                // Refresh file listing in case it's out of sync? It always uses current state
                renderFileList();
            });

            document.getElementById('open-notepad').addEventListener('click', function() {
                const win = document.getElementById('notepad-window');
                showWindow(win);
                // Ensure notepad UI reflects latest data (tabs, editor)
                updateNotepadUI();
            });

            // --- FILESYSTEM DATA ---
            const fileSystem = {
                name: '/',
                type: 'dir',
                children: {
                    bin: {
                        name: 'bin',
                        type: 'dir',
                        children: {
                            bash: { name: 'bash', type: 'file' },
                            ls: { name: 'ls', type: 'file' },
                            cat: { name: 'cat', type: 'file' }
                        }
                    },
                    etc: {
                        name: 'etc',
                        type: 'dir',
                        children: {
                            passwd: { name: 'passwd', type: 'file' },
                            hosts: { name: 'hosts', type: 'file' },
                            fstab: { name: 'fstab', type: 'file' }
                        }
                    },
                    home: {
                        name: 'home',
                        type: 'dir',
                        children: {
                            user: {
                                name: 'user',
                                type: 'dir',
                                children: {
                                    Documents: { name: 'Documents', type: 'dir', children: {} },
                                    Downloads: { name: 'Downloads', type: 'dir', children: {} },
                                    Pictures: { name: 'Pictures', type: 'dir', children: {} },
                                    'readme.txt': { name: 'readme.txt', type: 'file' }
                                }
                            }
                        }
                    },
                    usr: {
                        name: 'usr',
                        type: 'dir',
                        children: {
                            lib: { name: 'lib', type: 'dir', children: {} },
                            local: { name: 'local', type: 'dir', children: {} }
                        }
                    },
                    var: {
                        name: 'var',
                        type: 'dir',
                        children: {
                            log: { name: 'log', type: 'dir', children: {} },
                            tmp: { name: 'tmp', type: 'dir', children: {} }
                        }
                    }
                }
            };

            // Current navigation state
            let currentPathSegments = []; // empty = root
            let currentNode = fileSystem;

            function getNodeFromPath(segments) {
                let node = fileSystem;
                for (const seg of segments) {
                    if (!node.children || !node.children[seg]) return null;
                    node = node.children[seg];
                }
                return node;
            }

            function getAbsolutePath() {
                if (currentPathSegments.length === 0) return '/';
                return '/' + currentPathSegments.join('/');
            }

            function navigateTo(segments) {
                const node = getNodeFromPath(segments);
                if (!node || node.type !== 'dir') return; // shouldn't happen
                currentPathSegments = segments.slice();
                currentNode = node;
                renderFileList();
            }

            function navigateUp() {
                if (currentPathSegments.length === 0) return;
                const newSegments = currentPathSegments.slice(0, -1);
                navigateTo(newSegments);
            }

            // Render files in current directory
            function renderFileList() {
                const listEl = document.getElementById('files-list');
                const pathEl = document.getElementById('files-path');
                pathEl.textContent = getAbsolutePath();
                listEl.innerHTML = '';

                if (!currentNode.children) return;

                const sortedKeys = Object.keys(currentNode.children).sort((a, b) => {
                    const aIsDir = currentNode.children[a].type === 'dir';
                    const bIsDir = currentNode.children[b].type === 'dir';
                    if (aIsDir && !bIsDir) return -1;
                    if (!aIsDir && bIsDir) return 1;
                    return a.localeCompare(b);
                });

                sortedKeys.forEach(key => {
                    const item = currentNode.children[key];
                    const entryDiv = document.createElement('div');
                    entryDiv.className = 'fs-item ' + (item.type === 'dir' ? 'folder' : 'file');
                    entryDiv.dataset.name = key;
                    entryDiv.dataset.type = item.type;
                    entryDiv.textContent = key;
                    listEl.appendChild(entryDiv);
                });
            }

            // Double-click handler for file system items
            document.getElementById('files-list').addEventListener('dblclick', function(e) {
                const fsItem = e.target.closest('.fs-item');
                if (!fsItem) return;
                const name = fsItem.dataset.name;
                const type = fsItem.dataset.type;
                if (type === 'dir') {
                    const newSegments = currentPathSegments.concat([name]);
                    navigateTo(newSegments);
                } else {
                    // File double-click: optional action
                    alert(`File "${name}" - no application to open it.`);
                }
            });

            // Up button
            document.getElementById('files-up').addEventListener('click', navigateUp);

            // Initialize files listing on page load (though window hidden, prepare)
            renderFileList();

            // --- NOTEPAD LOGIC WITH LOCAL STORAGE ---
            const NOTEPAD_STORAGE_KEY = 'notepad-data';

            // Global state
            let notepadTabs = ['']; // default one empty tab
            let notepadActiveTab = 0;

            function loadNotepadData() {
                const stored = localStorage.getItem(NOTEPAD_STORAGE_KEY);
                if (stored) {
                    try {
                        const data = JSON.parse(stored);
                        if (Array.isArray(data.tabs) && data.tabs.length > 0) {
                            notepadTabs = data.tabs;
                            notepadActiveTab = data.activeTab >= 0 && data.activeTab < notepadTabs.length ? data.activeTab : 0;
                        }
                    } catch (e) {
                        // ignore, use defaults
                    }
                }
            }

            function saveNotepadData() {
                localStorage.setItem(NOTEPAD_STORAGE_KEY, JSON.stringify({
                    tabs: notepadTabs,
                    activeTab: notepadActiveTab
                }));
            }

            function updateNotepadUI() {
                const tabsContainer = document.getElementById('tabs');
                const editor = document.getElementById('editor');
                if (!tabsContainer || !editor) return;

                // Build tab elements
                tabsContainer.innerHTML = '';
                notepadTabs.forEach((content, idx) => {
                    const tab = document.createElement('div');
                    tab.className = 'tab' + (idx === notepadActiveTab ? ' active' : '');
                    tab.dataset.tabIndex = idx;
                    tab.textContent = `Tab ${idx + 1}`;
                    tabsContainer.appendChild(tab);
                });

                // Update editor content
                editor.value = notepadTabs[notepadActiveTab] || '';
            }

            // Switch to specific tab
            function switchTab(index) {
                if (index === notepadActiveTab) return;
                if (index < 0 || index >= notepadTabs.length) return;
                notepadActiveTab = index;
                updateNotepadUI();
                saveNotepadData();
            }

            // Handle tab click via delegation
            document.getElementById('tabs').addEventListener('click', function(e) {
                const tab = e.target.closest('.tab');
                if (!tab) return;
                const idx = parseInt(tab.dataset.tabIndex, 10);
                if (!isNaN(idx)) switchTab(idx);
            });

            // New tab button
            document.getElementById('new-tab').addEventListener('click', function() {
                notepadTabs.push('');
                notepadActiveTab = notepadTabs.length - 1;
                updateNotepadUI();
                saveNotepadData();
            });

            // Editor input handler
            const editorEl = document.getElementById('editor');
            editorEl.addEventListener('input', function() {
                if (notepadActiveTab >= 0 && notepadActiveTab < notepadTabs.length) {
                    notepadTabs[notepadActiveTab] = editorEl.value;
                    saveNotepadData();
                }
            });

            // Prevent tab switching when editor is focused and user types? No issue.

            // Initialize notepad data from localStorage on page load
            loadNotepadData();
            updateNotepadUI(); // apply
        })();
    </script>
</body>
</html>
